// NQxb_Gateway_v1__Normalize_Request
// Canonical normalization BEFORE Gatekeeper
// FIX: explicitly forward title + owner identity for artifact.save
// T123: Forward full raw payload for messaging.* actions

function isNonEmptyObject(v) {
  return v && typeof v === "object" && !Array.isArray(v) && Object.keys(v).length > 0;
}

function pickSource() {
  if (isNonEmptyObject($json?.params)) return { src: "params", raw: $json.params };
  if (isNonEmptyObject($json?.query)) return { src: "query", raw: $json.query };
  if (isNonEmptyObject($json?.body?.body)) return { src: "body.body", raw: $json.body.body };
  if (isNonEmptyObject($json?.body)) return { src: "body", raw: $json.body };
  if (isNonEmptyObject($json)) return { src: "json", raw: $json };
  return { src: "empty", raw: {} };
}

const { src, raw } = pickSource();

return [
  {
    json: {
      // --- Canonical action ---
      gw_action: raw.gw_action ?? raw.action ?? null,

      // --- Workspace / identity ---
      gw_workspace_id: raw.gw_workspace_id ?? raw.workspace_id ?? null,
      workspace_id: raw.workspace_id ?? raw.gw_workspace_id ?? null,

      // --- Artifact identity ---
      artifact_type: raw.artifact_type ?? null,
      artifact_id: raw.artifact_id ?? null,

      // --- REQUIRED for INSERT ---
      title: raw.title ?? null,

      // --- Payload ---
      extension: raw.extension ?? raw.patch ?? {},
      tags: raw.tags ?? null,

      // --- Spine fields for INSERT ---
      parent_artifact_id: raw.parent_artifact_id ?? null,
      summary: raw.summary ?? null,
      priority: raw.priority ?? null,
      content: raw.content ?? null,
      content_append: raw.content_append ?? null,
      content_mode: raw.content_mode ?? null,
      lifecycle_status: raw.lifecycle_status ?? null,
      execution_status: raw.execution_status ?? null,

      // --- Semantic type (T69 Phase 3) ---
      semantic_type_id: raw.semantic_type_id ?? null,

      // --- Owner / auth passthrough ---
      auth_username:
        raw.auth_username ??
        raw.owner_username ??
        raw.created_by ??
        null,

      // --- Freeze intent ---
      req_gw_workspace_id: raw.gw_workspace_id ?? raw.workspace_id ?? null,
      req_artifact_type: raw.artifact_type ?? null,
      req_artifact_id: raw.artifact_id ?? null,
      req_title: raw.title ?? null,

      // --- Selector (artifact.list pagination) ---
      selector: raw.selector ?? {},

      // --- Promote fields ---
      transition: raw.transition ?? null,
      reason: raw.reason ?? null,

      // --- T123: Forward full raw payload for messaging actions ---
      // Messaging sub-workflows extract their own fields from raw
      ...((/^messaging\./).test(raw.gw_action ?? '') ? raw : {}),

      _gw_debug: {
        normalized_by: "NQxb_Gateway_v1__Normalize_Request",
        source: src,
        received_keys: Object.keys(raw),
        has_title: !!raw.title,
        has_auth: !!(
          raw.auth_username ||
          raw.owner_username ||
          raw.created_by
        ),
      },

      gateway_meta: {
        processed_at: new Date().toISOString(),
        gateway_version: "v2_resolver",
      },
    },
  },
];

// NQxb_Gateway_v2__Gatekeeper
// Unified Gateway — workspace resolution via ACL lookup + legacy credential fallback
// Design: build-approved snapshot 5b4fb3e0

const ACTION_ALLOWLIST = new Set([
  "artifact.query",
  "artifact.list",
  "artifact.save",
  "artifact.update",
  "artifact.promote",
  "artifact.delete",
  "artifact.restore",
  "artifact.list_deleted",
  "messaging.send_email",
  "messaging.create_calendar_event",
]);

const TYPE_ALLOWLIST = new Set([
  "project",
  "journal",
  "restart",
  "snapshot",
  "instruction_pack",
  "branch",
  "limb",
  "leaf",
  "twig"
]);

// --- Known workspace IDs for validation ---
const KNOWN_WORKSPACES = new Set([
  "be0d3a48-c764-44f9-90c8-e846d9dbbd0a",  // Personal (Prime)
  "b4e7f648-96d5-44a7-80b9-c39cac4efbd1",  // BlaggLife
  "635bb8d7-7b93-4bea-8ca6-ee2c924c9557",  // Work (Resolve)
  "963973e0-a98c-4044-b421-71e7348eaeaf",  // Akara_Blagg
  "970d0df8-ab84-47f5-926c-3e784ba5dfa2",  // Qwrk_Greg
  "0af5712b-2534-47c1-8e28-45be4a2131dc",  // Explore Qwrk Demo
]);

// --- Legacy credential → workspace mapping (temporary, for migration) ---
const CREDENTIAL_WORKSPACE_MAP = {
  "qwrk-gateway":     "be0d3a48-c764-44f9-90c8-e846d9dbbd0a",
  "qwrk-gw-work":     "635bb8d7-7b93-4bea-8ca6-ee2c924c9557",
  "qwrk-gw-blagglife":"b4e7f648-96d5-44a7-80b9-c39cac4efbd1",
  "qwrk-gw-akara":    "963973e0-a98c-4044-b421-71e7348eaeaf",
  "qwrk-gw-greg":     "970d0df8-ab84-47f5-926c-3e784ba5dfa2",
  "qwrk-gw-demo":     "0af5712b-2534-47c1-8e28-45be4a2131dc",
};

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

function fail(code, message, details = {}) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: { code, message, details },

        gw_action: $json?.gw_action ?? null,
        gw_workspace_id: $json?.gw_workspace_id ?? null,
        artifact_type: $json?.artifact_type ?? null,
        artifact_id: $json?.artifact_id ?? null,
        selector: asObj($json?.selector),
        gateway_meta: $json?.gateway_meta ?? undefined,
        _gw_debug: $json?._gw_debug ?? undefined,
        incoming: $json ?? {},
      },
    },
  ];
}

// ----- Canonical fields from Normalize_Request -----
const gw_action = $json?.gw_action ?? null;
let gw_workspace_id = $json?.gw_workspace_id ?? null;
const artifact_type = $json?.artifact_type ?? null;
const artifact_id = $json?.artifact_id ?? null;
const selector = asObj($json?.selector);

const extension = asObj($json?.extension);
const tags = asObj($json?.tags);

// ----- Basic action validation -----
if (!gw_action || typeof gw_action !== "string") {
  return fail("VALIDATION_ERROR", "Missing or invalid gw_action", {
    expected: "string",
    got: typeof gw_action,
  });
}

if (!ACTION_ALLOWLIST.has(gw_action)) {
  return fail("ACTION_NOT_ALLOWED", "gw_action not allowed", {
    gw_action,
    allowed: Array.from(ACTION_ALLOWLIST),
  });
}

// ----- Workspace resolution (DESIGN CHANGE #2 + #3) -----
// Priority: explicit workspace_id > legacy credential fallback
const requiresWorkspaceAtGate = gw_action !== "artifact.update";

if (requiresWorkspaceAtGate) {
  // Try explicit workspace_id first (resolver mode)
  if (!gw_workspace_id || typeof gw_workspace_id !== "string") {
    // Fallback: derive from credential (legacy mode)
    const auth_username = $json?.auth_username ?? null;
    if (auth_username && CREDENTIAL_WORKSPACE_MAP[auth_username]) {
      gw_workspace_id = CREDENTIAL_WORKSPACE_MAP[auth_username];
    } else {
      return fail("WORKSPACE_INVALID", "Invalid request context", {
        _internal_reason: "No workspace_id in payload and no valid credential fallback",
      });
    }
  }

  // Validate workspace exists (DESIGN CHANGE #2: strict ACL check)
  if (!KNOWN_WORKSPACES.has(gw_workspace_id)) {
    return fail("WORKSPACE_INVALID", "Invalid request context", {
      _internal_reason: "workspace_id not in known workspaces",
    });
  }
}

// ----- artifact.query -----
if (gw_action === "artifact.query") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail(
      "VALIDATION_ERROR",
      "Missing or invalid artifact_type for artifact.query"
    );
  }

  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }

  if (!artifact_id || typeof artifact_id !== "string") {
    return fail(
      "VALIDATION_ERROR",
      "Missing or invalid artifact_id for artifact.query"
    );
  }
}

// ----- artifact.list -----
if (gw_action === "artifact.list") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail(
      "VALIDATION_ERROR",
      "Missing or invalid artifact_type for artifact.list"
    );
  }

  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }

  if (selector.limit !== undefined) {
    const n = Number(selector.limit);
    if (!Number.isFinite(n) || n < 1 || n > 100) {
      return fail("VALIDATION_ERROR", "selector.limit out of range (1-100)", {
        limit: selector.limit,
      });
    }
  }
}

// ----- artifact.update -----
if (gw_action === "artifact.update") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail(
      "VALIDATION_ERROR",
      "Missing or invalid artifact_type for artifact.update"
    );
  }

  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }

  if (!artifact_id || typeof artifact_id !== "string") {
    return fail(
      "VALIDATION_ERROR",
      "Missing or invalid artifact_id for artifact.update"
    );
  }

  const hasExtension = Object.keys(extension).length > 0;

  const hasTags =
    (Array.isArray(tags?.add) && tags.add.length > 0) ||
    (Array.isArray(tags?.remove) && tags.remove.length > 0);

  const spineFieldCandidates = [
    "title",
    "summary",
    "priority",
    "lifecycle_status",
    "parent_artifact_id"
  ];

  const hasSpineFields = spineFieldCandidates.some((f) => {
    const val = $json?.[f];
    return val !== null && val !== undefined;
  });

  // T140: Content field detection for update validation
  const hasContent = $json?.content !== null && $json?.content !== undefined
    && typeof $json?.content === 'object' && !Array.isArray($json?.content)
    && Object.keys($json.content).length > 0;
  const hasContentAppend = $json?.content_append !== null && $json?.content_append !== undefined
    && typeof $json?.content_append === 'object' && !Array.isArray($json?.content_append);

  if (!hasExtension && !hasTags && !hasSpineFields && !hasContent && !hasContentAppend) {
    return fail(
      "VALIDATION_ERROR",
      "artifact.update requires extension, tags, spine fields, content, or content_append",
      {
        expected:
          "extension OR tags.add/remove OR title/summary/priority/lifecycle_status OR content OR content_append",
      }
    );
  }
}

// ----- PASS THROUGH -----
return [
  {
    json: {
      ...($json ?? {}),

      ok: true,
      _gw_route: "ok",

      gw_action,
      gw_workspace_id: gw_workspace_id ?? null,
      workspace_id: gw_workspace_id ?? null,
      artifact_type: artifact_type ?? null,
      artifact_id: artifact_id ?? null,
      selector,

      ...(gw_action === "artifact.update"
        ? {
            extension,
            tags,

            spine_fields: (() => {
              const sf = {};
              if ($json?.title !== null && $json?.title !== undefined)
                sf.title = $json.title;
              if ($json?.summary !== null && $json?.summary !== undefined)
                sf.summary = $json.summary;
              if ($json?.priority !== null && $json?.priority !== undefined)
                sf.priority = $json.priority;
              if (
                $json?.lifecycle_status !== null &&
                $json?.lifecycle_status !== undefined
              )
                sf.lifecycle_status = $json.lifecycle_status;
              if (
                $json?.parent_artifact_id !== null &&
                $json?.parent_artifact_id !== undefined
              )
                sf.parent_artifact_id = $json.parent_artifact_id;

              return Object.keys(sf).length > 0 ? sf : null;
            })(),
          }
        : {}),

      gateway_meta: $json?.gateway_meta ?? undefined,
      _gw_debug: $json?._gw_debug ?? undefined,
    },
  },
];

